     7→// Get user's available assessments
     8→router.get('/available', authMiddleware, async (req, res) => {
     9→  try {
    10→    const userId = req.user.id;
    11→
    12→    // Get user's skills that don't have verified assessments
    13→    const result = await pool.query(`
    14→      SELECT cs.id, cs.skill_name, cs.category, cs.level, cs.is_verified,
    15→             COUNT(sa.id) as assessment_count,
    16→             MAX(sa.score) as best_score
    17→      FROM candidate_skills cs
    18→      LEFT JOIN skill_assessments sa ON cs.id = sa.skill_id AND sa.completed_at IS NOT NULL
    19→      WHERE cs.user_id = $1
    20→      GROUP BY cs.id
    21→      ORDER BY cs.is_verified ASC, cs.created_at DESC
    22→    `, [userId]);
    23→
    24→    res.json({ skills: result.rows });
    25→  } catch (error) {
    26→    console.error('Error fetching available assessments:', error);
    27→    res.status(500).json({ error: 'Failed to fetch assessments' });
    28→  }
    29→});
