    31→// Get past assessment results
    32→router.get('/results', authMiddleware, async (req, res) => {
    33→  try {
    34→    const userId = req.user.id;
    35→
    36→    const result = await pool.query(`
    37→      SELECT sa.*, cs.skill_name, cs.category,
    38→             ass.tab_switches, ass.copy_paste_attempts, ass.time_anomalies,
    39→             ass.max_difficulty_reached
    40→      FROM skill_assessments sa
    41→      LEFT JOIN candidate_skills cs ON sa.skill_id = cs.id
    42→      LEFT JOIN assessment_sessions ass ON sa.session_id = ass.id
    43→      WHERE sa.user_id = $1 AND sa.completed_at IS NOT NULL
    44→      ORDER BY sa.completed_at DESC
    45→    `, [userId]);
    46→
    47→    res.json({ results: result.rows });
    48→  } catch (error) {
    49→    console.error('Error fetching assessment results:', error);
    50→    res.status(500).json({ error: 'Failed to fetch results' });
    51→  }
    52→});
