    54→// Start new assessment
    55→router.post('/start', authMiddleware, async (req, res) => {
    56→  const client = await pool.connect();
    57→  try {
    58→    const userId = req.user.id;
    59→    const { skillId, jobId } = req.body;
    60→
    61→    if (!skillId) {
    62→      return res.status(400).json({ error: 'Skill ID required' });
    63→    }
    64→
    65→    await client.query('BEGIN');
    66→
    67→    // Get skill details
    68→    const skillResult = await client.query(
    69→      'SELECT * FROM candidate_skills WHERE id = $1 AND user_id = $2',
    70→      [skillId, userId]
    71→    );
    72→
    73→    if (skillResult.rows.length === 0) {
    74→      await client.query('ROLLBACK');
    75→      return res.status(404).json({ error: 'Skill not found' });
    76→    }
    77→
    78→    const skill = skillResult.rows[0];
    79→
    80→    // Create assessment session
    81→    const sessionResult = await client.query(`
    82→      INSERT INTO assessment_sessions
    83→      (user_id, skill_id, job_id, current_difficulty, started_at)
    84→      VALUES ($1, $2, $3, 2, NOW())
    85→      RETURNING *
    86→    `, [userId, skillId, jobId || null]);
    87→
    88→    const session = sessionResult.rows[0];
    89→
    90→    // Generate first question
    91→    const question = await generateQuestion(skill.skill_name, skill.category, 2, client);
    92→
    93→    // Record question asked
    94→    const questionsAsked = [{ questionId: question.id, difficulty: question.difficulty_level, timestamp: new Date() }];
    95→    await client.query(
    96→      'UPDATE assessment_sessions SET questions_asked = $1, current_question_index = 1 WHERE id = $2',
    97→      [JSON.stringify(questionsAsked), session.id]
    98→    );
    99→
   100→    await client.query('COMMIT');
   101→
   102→    res.json({
   103→      sessionId: session.id,
   104→      question: {
   105→        id: question.id,
   106→        text: question.question_text,
   107→        type: question.question_type,
   108→        options: question.options,
   109→        timeLimit: question.time_limit_seconds,
   110→        questionNumber: 1,
   111→        totalQuestions: 10
   112→      }
   113→    });
   114→  } catch (error) {
   115→    await client.query('ROLLBACK');
   116→    console.error('Error starting assessment:', error);
   117→    res.status(500).json({ error: 'Failed to start assessment' });
   118→  } finally {
   119→    client.release();
   120→  }
   121→});
