   279→// Log anti-cheat event
   280→router.post('/event', authMiddleware, async (req, res) => {
   281→  try {
   282→    const userId = req.user.id;
   283→    const { sessionId, eventType, eventData } = req.body;
   284→
   285→    // Verify session belongs to user
   286→    const sessionResult = await pool.query(
   287→      'SELECT id FROM assessment_sessions WHERE id = $1 AND user_id = $2',
   288→      [sessionId, userId]
   289→    );
   290→
   291→    if (sessionResult.rows.length === 0) {
   292→      return res.status(404).json({ error: 'Session not found' });
   293→    }
   294→
   295→    // Log event
   296→    await pool.query(`
   297→      INSERT INTO assessment_events (session_id, event_type, event_data)
   298→      VALUES ($1, $2, $3)
   299→    `, [sessionId, eventType, eventData]);
   300→
   301→    // Update session counters
   302→    if (eventType === 'tab_switch') {
   303→      await pool.query(
   304→        'UPDATE assessment_sessions SET tab_switches = tab_switches + 1 WHERE id = $1',
   305→        [sessionId]
   306→      );
   307→    } else if (eventType === 'copy_paste') {
   308→      await pool.query(
   309→        'UPDATE assessment_sessions SET copy_paste_attempts = copy_paste_attempts + 1 WHERE id = $1',
   310→        [sessionId]
   311→      );
   312→    }
   313→
   314→    res.json({ logged: true });
   315→  } catch (error) {
   316→    console.error('Error logging event:', error);
   317→    res.status(500).json({ error: 'Failed to log event' });
   318→  }
   319→});
